def transport(self) -> transports.Transport:
    if self.kind not in TRANSPORTS:
        raise NotImplementedError(f"Unknown channel kind: {self.kind}")

    label, cls = TRANSPORTS[self.kind]
    # import transport classes on first use, and cache in TRANSPORTS
    if isinstance(cls, str):
        modulename, classname = cls.rsplit(".", maxsplit=1)
        cls = getattr(import_module(modulename), classname)
        TRANSPORTS[self.kind] = (label, cls)

    return cls(self)

def notify(self, flip: Flip, is_test: bool = False) -> str:
    if self.transport.is_noop(flip.new_status):
        return "no-op"

    n = Notification(channel=self)
    if is_test:
        # When sending a test notification we leave the owner field null.
        # (the passed check is a dummy, unsaved Check instance)
        pass
    else:
        n.owner = flip.owner

    n.check_status = flip.new_status
    n.error = "Sending"
    try:
        n.save()
    except IntegrityError:
        return "Channel or check does not exist any more"

    start, error, disabled = now(), "", self.disabled
    try:
        self.transport.notify(flip, notification=n)

    except transports.TransportError as e:
        disabled = True if e.permanent else disabled
        error = e.message

class Slackalike(HttpTransport):
    """Base class for transports that use Slack-compatible incoming webhooks."""

    def payload(self, flip: Flip) -> JSONDict:
        """Prepare JSON-serializable payload for Slack-compatible incoming webhook."""
        check = flip.owner
        name = check.name_then_code()
        fields = SlackFields()
        text = None
        if flip.reason:
            text = f"Reason: {flip.reason_long()}." if flip.reason else None
        elif flip.new_status == "up" and flip.down_duration:
            formatted_duration = format_duration_for_sentence(flip.down_duration)
            text = f"The downtime lasted {formatted_duration}."

        result: JSONDict = {
            "username": settings.SITE_NAME,
            "icon_url": absolute_site_logo_url(),
            "attachments": [
                {
                    "color": "good" if flip.new_status == "up" else "danger",
                    "fallback": f'The check "{name}" is {flip.new_status.upper()}.',
                    "mrkdwn_in": ["fields"],
                    "title": f"“{name}” is {flip.new_status.upper()}.",
                    "title_link": check.cloaked_url(),
                    "text": text,
                    "fields": fields,
                }
            ],
        }
